async function seedService(copy: ServiceCopy) {
  const svc = await sql`SELECT id FROM services WHERE slug = ${copy.slug} LIMIT 1`;
  if (!svc[0]) { console.error(`Service "${copy.slug}" not found — skip`); return; }
  const serviceId = svc[0].id as string;

  await sql`UPDATE services SET summary_uk=${copy.summary.uk}, summary_ru=${copy.summary.ru}, summary_en=${copy.summary.en} WHERE id=${serviceId}`;
  await sql`DELETE FROM content_sections WHERE owner_type='service' AND owner_id=${serviceId}`;
  await sql`DELETE FROM faq_items WHERE owner_type='service' AND owner_id=${serviceId}`;

  const sectionIds: string[] = [];
  for (let i = 0; i < copy.sections.length; i++) {
    const s = copy.sections[i];
    const id = randomUUID();
    sectionIds.push(id);
    const data = { heading: s.heading, body: s.body, calloutBody: s.calloutBody, heroImage: null };
    await sql`INSERT INTO content_sections(id,owner_type,owner_id,sort_order,section_type,data) VALUES(${id},'service',${serviceId},${i},'richText'::section_type,${JSON.stringify(data)}::jsonb)`;
  }
  for (let i = 0; i < copy.faq.length; i++) {
    const f = copy.faq[i];
    await sql`INSERT INTO faq_items(owner_type,owner_id,sort_order,question_uk,question_ru,question_en,answer_uk,answer_ru,answer_en) VALUES('service',${serviceId},${i},${f.question.uk},${f.question.ru},${f.question.en},${f.answer.uk},${f.answer.ru},${f.answer.en})`;
  }

  const newOrder = [...sectionIds.map(id => `section:${id}`), "faq", "doctors", "equipment", "relatedServices", "finalCTA"];
  await sql`UPDATE services SET block_order=${newOrder} WHERE id=${serviceId}`;
  console.log(`✓ ${copy.slug} — ${copy.sections.length} sections, ${copy.faq.length} FAQs`);
}

async function main() {
  for (const svc of SERVICES) await seedService(svc);
  await sql.end();
  console.log("\nV3c DONE — M22 Stellar Black, Splendor X, HydraFacial, AcuPulse CO₂.");
  console.log("All 11 apparatus-cosmetology services have copy. Continue with V4 for intimate-rejuvenation, laser-hair-removal, and longevity categories.");
}
main().catch(e => { console.error(e); process.exit(1); });
